import{_ as e,o as t,c as p,j as r,a as b,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"少女乐队专长","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/社交类/少女乐队专长.md","filePath":"4.资源分区/6.技艺及称号/社交类/少女乐队专长.md"}'),s={name:"4.资源分区/6.技艺及称号/社交类/少女乐队专长.md"};function n(_,a,d,l,i,c){return t(),p("div",null,[...a[0]||(a[0]=[r("h1",{id:"少女乐队专长",tabindex:"-1"},[b("少女乐队专长 "),r("a",{class:"header-anchor",href:"#少女乐队专长","aria-label":'Permalink to "少女乐队专长"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="少女乐队专长-1" tabindex="-1">少女乐队专长 <a class="header-anchor" href="#少女乐队专长-1" aria-label="Permalink to &quot;少女乐队专长&quot;">​</a></h1><p>少女乐队<br> 你是一位玩乐队的少女，擅长用自己的乐声打动别人，当然，即使你生理上不是女的也能购买此专长。</p><p>1级：感染心灵<br> 你习得一种使用乐器演奏乐曲来影响他人的方法，使用智力+表达：（任意一种乐器）+辅助专业：乐理学（学识）专业来进行检定，具有15m基础射程，伤害类型为精神。</p><p>2级：声乐练习<br> 舞台，不对，乐队少女日益精进自己，每场影片过后，你获得表达技能上的1点加值<br> 此外，你终于开始物色你将要演奏的乐器（包括麦克风），选定一种乐器，你使对应的武器获得3L武器伤害提升，可以将武器伤害加入到任何歌唱/乐器系新建攻击中使用。</p><p>3级：乐器选择<br> 经过长久的练习，你终于掌握了一门乐器的演奏技巧，购买此等级的专长后从下列乐器中选择一项，根据你选择的乐器获得对应的特性。<br> ①主唱<br> 你的歌声就是你内心的呐喊，代表着你的思想与意志。<br> 同一队伍内只能有一名主唱，若有多个强化这一专长的单位，则这些单位在使用本专长前，需要进行一次【表达+任意乐器专业】进行对抗，仅出目最高者可生效。<br> 释放的意志越多，你的歌声越有穿透力，你每有3点已使用的意志力，就使你的表达检定攻击获得1点【破甲】，向下取整。结算破防后如果还有剩余则转换为攻击DP上的增强加值。<br> 积蓄的意志越多，你的歌声越有压迫力，你每有3点未使用的意志力，就使你的表达检定攻击获得1点【威猛】，向下取整。结算破防后如果还有剩余则转换为攻击DP上的增强加值。<br> 意志值计算中只计入决心和沉着提供的意志，其他能力带来的意志提升不计入效果。</p><p>②伴唱<br> 你的声音能丰富歌曲的层次，作为辅助让整体更加和谐<br> 每轮一次，当你的表达攻击射程范围内有一位同伴使用表达攻击检定时，你可以用反射为对方伴唱，这个反射动作会透支你的下一轮移动动作<br> 这会使对方的此次检定可以再投掷1次选择更好的结果。<br> 无论如何，每轮对方只能受到一次伴唱的辅助效果。</p><p>③主音吉他手<br> 你是乐队里最亮眼也是最独立的存在，一场炫酷的solo绝对能吸引别人的眼球<br> 你使用智力+器用：乐器检定造成的伤害附带出目四分之一的魅惑点数，向下取整，意志豁免。<br> 被你命中的目标会深深被你的音乐吸引，他的一切行动目标都优先改为你，这是一个C级的支配效果</p><p>④节奏吉他手<br> 你负责提供和弦的基础和节奏支持，你擅长将多种旋律调和在一起，发挥更好的效果。<br> 每轮一次，当你的表达攻击射程范围内有一位除你以外的同伴使用表达攻击检定时，你可以用反射为对方弹奏和弦。</p><p>若对方的此次检定中附带有至少1种D级特性/效果，则此次检定获得【9加骰】<br> 若对方的此次检定中附带有至少1种C级特性/效果，则此次检定获得【8加骰】</p><p>⑤贝斯手<br> 你是乐队中节奏的延伸，负责衔接中低音部分。<br> 当你忘我地弹奏起贝斯时，你的氛围会和贝斯融为一体，变得毫无存在感，虽然这很令人挫败，但是你可以用【表达+任意一种乐器】代替【隐秘+潜藏】来进行潜藏检定<br> 此外，身为一名贝斯手，你还要负责承担起乐队里跳舞、拿外卖、搬器材等工作，这使你的运动技能获得2个的附加成功。</p><p>⑥鼓手<br> 你是乐队的根基与指挥，你的节拍引领着乐队向前<br> 长时间打鼓使你对钝击攻击有着非同常人的理解，你可以持有近战武器，把敌人当作架子鼓进行演奏。<br> 现在你可以选择一种近战武器（伤害性质需为钝击），以1级专长的攻击检定来使用这一种武器进行近战攻击，当你持用这一种武器进行攻击时，你的传奇力量每有1点，就使你的攻击获得3L武器伤害的提升。</p><p>⑦键盘手<br> 你的键盘能给乐队带来更丰富的音色层次，借助合成器，你几乎可以提供乐队里的所有声音。<br> 每2个影片后，你可以习得本专长中的一个3级专长。</p><p>团队演出（3）<br> 3级：你和你的伙伴们组成团体，<br> 你的智力+器用：乐器检定进行的攻击转变为以你为中心的圆形范围伤害，射程为3.75M。<br> 每场影片结束后，你们如果至少进行了一场演出，则你获得5声望提升和250分数作为营业额。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',15)])])}const f=e(s,[["render",n]]);export{m as __pageData,f as default};
